                tdRevSurah.appendChild(revSurahSelect);
                tr.appendChild(tdRevSurah);

                const tdRevPages = document.createElement('td');
                tdRevPages.dataset.label = 'عدد صفحات المراجعة الكبرى';
                const revPagesInput = document.createElement('input');
                revPagesInput.type = 'number';
                revPagesInput.min = '1';
                revPagesInput.value = isNaN(defaultRevPages) ? '5' : String(defaultRevPages);
