        function getAbsoluteAyahNumber(surahIndex, ayahNumber) {
            const surah = QuranData.Sura[surahIndex];
            return surah[0] + ayahNumber;
        }

        function getSurahAndAyahFromAbsolute(absoluteAyah) {
            // Ignore the technical sentinel entry after سورة الناس and
            // always resolve within the 114 real surahs.
            const LAST_REAL_SURAH_INDEX = 114;

            for (let i = 1; i <= LAST_REAL_SURAH_INDEX; i++) {
                const surah = QuranData.Sura[i];
                const nextSurah = i < LAST_REAL_SURAH_INDEX ? QuranData.Sura[i + 1] : null;

                if (nextSurah && absoluteAyah >= surah[0] && absoluteAyah < nextSurah[0]) {
                    let ayah = absoluteAyah - surah[0];
                    if (ayah < 1) ayah = 1;
                    if (ayah > surah[1]) ayah = surah[1];
                    return {
                        surah: i,
                        ayah,
                        surahName: surah[4],
                        totalAyahs: surah[1]
                    };
                } else if (!nextSurah && absoluteAyah >= surah[0]) {
                    let ayah = absoluteAyah - surah[0];
                    if (ayah < 1) ayah = 1;
                    if (ayah > surah[1]) ayah = surah[1];
                    return {
                        surah: i,
                        ayah,
                        surahName: surah[4],
                        totalAyahs: surah[1]
                    };
                }
            }
            return null;
        }

        function getPageForAyah(surahIndex, ayahNumber) {
            const absoluteAyah = getAbsoluteAyahNumber(surahIndex, ayahNumber);

            for (let i = 1; i < QuranData.Page.length; i++) {
                const currentPage = QuranData.Page[i];
                const nextPage = QuranData.Page[i + 1];

                const currentAbsolute = getAbsoluteAyahNumber(currentPage[0], currentPage[1]);

                if (nextPage) {
                    const nextAbsolute = getAbsoluteAyahNumber(nextPage[0], nextPage[1]);
                    if (absoluteAyah >= currentAbsolute && absoluteAyah < nextAbsolute) {
                        return i;
                    }
                } else {
                    if (absoluteAyah >= currentAbsolute) {
                        return i;
                    }
                }
            }
            return 604;
        }

        function create30DayPlan(config) {
            const days = [];
            const usesMemorization = config.memPlan !== "none";
            const planKey = usesMemorization ? planValueToKey(config.memPlan) : null;
            const planData = usesMemorization ? memorizationData[planKey] : null;
            const startIndex = usesMemorization ? config.memStartIndex : 0;

            const totalPages = getRealPageCount();
            const bigStartPage = Math.min(getPageForAyah(config.bigRevSurah, config.bigRevAyah), totalPages);
            const bigReviewSchedule = buildReviewSchedule(config.bigRevSurah, config.bigRevAyah, config.bigReviewPages, null, bigStartPage, totalPages);

            // Minor review window ends just before big review start page (wraps around if needed)
            const minorEndPage = bigStartPage === 1 ? totalPages : bigStartPage - 1;
            const minorReviewSchedule = usesMemorization ? null : buildReviewSchedule(
                config.minorReviewSurah,
                config.minorReviewAyah,
                config.minorReviewPages,
                minorEndPage,
                null,
                totalPages
            );

            for (let day = 1; day <= TOTAL_PLAN_DAYS; day++) {
                const memIndex = startIndex + day - 1;

                const dayPlan = {
                    day: day,
                    memorization: '',
                    minorReview: '',
                    bigReview: []
                };

                if (usesMemorization && planData) {
                    dayPlan.memorization = memIndex < planData.data.length ? planData.data[memIndex] : '';

                    if (day > 1) {
                        const prevMemIndex = startIndex + day - 2;
                        dayPlan.minorReview = prevMemIndex < planData.data.length ? planData.data[prevMemIndex] : '';
                    }
                } else if (minorReviewSchedule) {
                    const minorRange = computeRangeForDay(minorReviewSchedule, day);
                    if (minorRange) {
                        dayPlan.minorReview = formatBigReviewText(minorRange);
                    }
                }

                const bigRange = computeRangeForDay(bigReviewSchedule, day);
                if (bigRange) {
                    dayPlan.bigReview.push(bigRange);
                }

                days.push(dayPlan);
            }

            return {
                studentId: config.studentId || '',
                studentName: config.studentName,
                memPlan: config.memPlan,
                memStartEntry: usesMemorization && planData ? planData.data[startIndex] : '',
                minorReviewPages: !usesMemorization ? config.minorReviewPages : null,
                bigRevStartPage: bigReviewSchedule.startPage,
                bigReviewPages: config.bigReviewPages,
                days: days
            };
        }

        function formatBigReviewText(item) {
            let fromText = item.from.surahName;
            let toText = item.to.surahName;

            // Don't show ayah 1 if starting from beginning
            if (item.from.ayah !== 1) {
                fromText += ` ${item.from.ayah}`;
            }

            // Don't show ayah if ending at last ayah of previous surah
            // (which means we're at ayah 0 of next surah conceptually)
            if (item.to.ayah !== 0 && item.to.ayah !== item.to.totalAyahs) {
                toText += ` ${item.to.ayah}`;
            }

            return `${fromText} ← ${toText}`;
        }

        function displayPlan(plan) {
            if (!plan) return;

            const container = document.getElementById('planDisplay');

            const planName = planValueToLabel(plan.memPlan);
            const memStartText = plan.memStartEntry ? ` | بداية: ${plan.memStartEntry}` : '';
            const minorReviewText = plan.minorReviewPages ? ` | المراجعة الصغرى: ${plan.minorReviewPages} صفحات يومياً` : '';

            let html = `
                <div class="plan-header">
                    <h2>خطة الطالب: ${plan.studentName}</h2>
                    <p>خطة الحفظ: ${planName}${memStartText}${minorReviewText}</p>
                    <p>المراجعة الكبرى: ${plan.bigReviewPages} صفحات يومياً من صفحة ${plan.bigRevStartPage}</p>
                </div>

                <div class="days-grid">
            `;

            plan.days.forEach(day => {
                html += `
                    <div class="day-card">
                        <div class="day-header">
                            <span class="day-number">اليوم ${day.day}</span>
                        </div>
                        <div class="day-content">
                `;

                // Memorization
                if (day.memorization) {
                    html += `
                        <div class="section">
                            <div class="section-title">📖 الحفظ</div>
                            <div class="section-content">
                                ${day.memorization}
                            </div>
                        </div>
                    `;
                }

                // Minor Review
                if (day.minorReview) {
                    html += `
                        <div class="section">
                            <div class="section-title">🔄 المراجعة الصغرى</div>
                            <div class="section-content">
                                ${day.minorReview}
                            </div>
                        </div>
                    `;
                } else if (day.day === 1 && plan.memPlan !== 'none') {
                    html += `
                        <div class="section">
                            <div class="section-title">🔄 المراجعة الصغرى</div>
                            <div class="section-content" style="color: #999; font-style: italic;">
                                لا يوجد (اليوم الأول)
                            </div>
                        </div>
                    `;
                }

                // Big Review
                if (day.bigReview.length > 0) {
                    html += `
                        <div class="section">
                            <div class="section-title">📚 المراجعة الكبرى</div>
                            <div class="section-content">
                    `;
                    day.bigReview.forEach(item => {
                        html += `
                            <div class="ayah-range">
                                <span>${formatBigReviewText(item)}</span>
                            </div>
                            <div style="text-align: center; color: var(--primary); font-weight: 600; margin-top: 0.5rem;">
                                صفحة ${item.startPage} - ${item.endPage}
                            </div>
                        `;
                    });
                    html += `</div></div>`;
                }

                html += `</div></div>`;
            });

            html += `</div>`;

            container.innerHTML = html;
            container.classList.add('active');
            container.scrollIntoView({ behavior: 'smooth' });
        }

        function buildPlansHTMLFromRows(rows) {
            if (!memorizationData) {
                alert('جاري تحميل بيانات الحفظ... الرجاء المحاولة مرة أخرى');
                return '';
            }
            let html = '';

            rows.forEach((row, index) => {
                const studentId = row.dataset.studentId || '';
                const studentName = row.dataset.studentName || '';

                const memStartSelect = row.querySelector('.student-mem-start');
                const memAmountSelect = row.querySelector('.student-mem-amount');
                const reviewOnlyToggle = row.querySelector('.student-review-only');
                const minorSurahSelect = row.querySelector('.student-minor-surah');
                const minorAyahSelect = row.querySelector('.student-minor-ayah');
                const minorPagesInput = row.querySelector('.student-minor-pages');
                const revSurahSelect = row.querySelector('.student-rev-surah');
                const revPagesInput = row.querySelector('.student-rev-pages');

                const memStartIndex = memStartSelect ? parseInt(memStartSelect.value) : 0;
                const reviewOnly = reviewOnlyToggle ? reviewOnlyToggle.checked : false;
                let memPlan = memAmountSelect ? memAmountSelect.value : (document.querySelector('input[name="memPlan"]:checked').value);
                if (reviewOnly || memPlan === 'none') {
                    memPlan = 'none';
                }
                const bigRevSurah = revSurahSelect ? parseInt(revSurahSelect.value) : 78;
                const bigRevAyah = 1;
                const bigReviewPages = revPagesInput ? parseInt(revPagesInput.value) : 5;
                const minorReviewSurah = minorSurahSelect ? parseInt(minorSurahSelect.value) : bigRevSurah;
                const minorReviewAyah = minorAyahSelect ? parseInt(minorAyahSelect.value) : bigRevAyah;
                const minorReviewPages = minorPagesInput ? parseInt(minorPagesInput.value) : 2;

                const plan = create30DayPlan({
                    studentId,
                    studentName,
                    memPlan,
                    memStartIndex,
                    bigRevSurah,
                    bigRevAyah,
                    bigReviewPages,
                    minorReviewSurah,
                    minorReviewAyah,
                    minorReviewPages
                });

                currentPlan = plan; // keep last one for any other use
                const planName = planValueToLabel(plan.memPlan);
                // const memStartText = plan.memStartEntry ? ` | بداية: ${plan.memStartEntry}` : '';
                const minorReviewText = plan.minorReviewPages ? `  المراجعة الصغرى: ${plan.minorReviewPages} صفحات يومياً` : '';

                html += `
                    <div class="pdf-page">
                        <div class="pdf-header">
                            <img src="${PDF_LOGO_URL}" alt="الشعار" class="pdf-header-logo">
                            <h1>الــخــطــة الــقــرآنــيــة</h1>
                            <p style="font-size: 1.1rem; margin-top: 1px; text-align: right; direction: rtl;"><strong>اسم الطالب:</strong> ${plan.studentName}&nbsp;&nbsp; | &nbsp;&nbsp;<strong>رقم الطالب:</strong> ${plan.studentId}</p>
                            <p style="font-size: 1rem; text-align: right; direction: rtl;"><strong>خطة الحفظ:</strong> ${planName}${minorReviewText}&nbsp;&nbsp; | &nbsp;&nbsp;<strong>المراجعة الكبرى:</strong> ${plan.bigReviewPages} صفحات يومياً</p>
                        </div>

                        <table class="pdf-table">
                            <thead>
                                <tr>
                                    <th style="width: 40px;">اليوم</th>
                                    <th>الحفظ</th>
                                    <th style="width: 15px;">انجز</th>
                                    <th>المراجعة الصغرى</th>
                                    <th style="width: 15px;">انجز</th>
                                    <th>المراجعة الكبرى</th>
                                    <th style="width: 15px;">انجز</th>
                                    <th style="width: 100px;">التهيئة</th>
                                    </tr>
                            </thead>
                            <tbody>
                `;

                plan.days.forEach(day => {
                    html += `<tr>`;
                    html += `<td class="pdf-day-header">${day.day}</td>`;
                    html += `<td class="pdf-main-text-cell pdf-memorization-cell">`;
                    if (day.memorization) {
                        html += `<div class="pdf-main-text-line">${day.memorization}</div>`;
                    } else {
                        html += '<span class="pdf-cell-placeholder">-</span>';
                    }
                    html += `</td>`;
                    html += `<td></td>`;// الإنجاز للحفظ
                    html += `<td class="pdf-main-text-cell pdf-minor-review-cell">`;
                    if (day.minorReview) {
                        html += `<div class="pdf-main-text-line">${day.minorReview}</div>`;
                    } else if (day.day === 1) {
                        html += '<span class="pdf-cell-note">لا يوجد</span>';
                    } else {
                        html += '<span class="pdf-cell-placeholder">-</span>';
                    }
                    html += `</td>`;
                    html += `<td></td>`; // الإنجاز للمراجعة الصغرى

                    html += `<td class="pdf-big-review-cell">`;
                    if (day.bigReview.length > 0) {
                        const bigReviewLines = day.bigReview
                            .map(item => `<div class="pdf-big-review-line">${formatBigReviewText(item)}</div>`)
                            .join('');
                        html += bigReviewLines;
                    } else {
                        html += '<span class="pdf-cell-placeholder">-</span>';
                    }
                    html += `</td>`;
                    html += `<td></td>`; // الإنجاز للمراجعة الكبرى
                    html += `<td></td>`; // التهيئة

                    html += `</tr>`;
                });

                html += `</tbody></table></div>`;
            });

            return html;
        }

        async function downloadSelectedAsPDF(buttonElement) {
            const allRows = Array.from(document.querySelectorAll('#studentsTable tbody tr'));
            if (allRows.length === 0) {
                alert('الرجاء إدخال بيانات الطالب أولاً');
                return;
            }

            const rows = isSingleStudentContext ? [allRows[0]] : allRows;

            // Find the button element
            const btn = buttonElement || event.target;
            const originalText = btn.textContent;

            try {
                // Show loading message
                btn.textContent = `⏳ جاري إنشاء PDF... (0/${rows.length})`;
                btn.disabled = true;

                const { jsPDF } = window.jspdf;
                const pdf = new jsPDF('p', 'mm', 'a4');

                const pdfContainer = document.getElementById('pdfContainer');
                pdfContainer.style.position = 'absolute';
                pdfContainer.style.left = '-9999px';
                pdfContainer.style.top = '0';
                pdfContainer.style.width = '210mm';
                pdfContainer.style.background = 'white';
                pdfContainer.style.padding = '10mm';

                for (let i = 0; i < rows.length; i++) {
                    // Update progress
                    btn.textContent = `⏳ جاري إنشاء PDF... (${i + 1}/${rows.length})`;

                    const row = rows[i];
                    const html = buildPlansHTMLFromRows([row]);
                    if (!html) continue;

                    pdfContainer.innerHTML = html;
                    pdfContainer.style.display = 'block';
                    pdfContainer.style.visibility = 'visible';

                    // Reduced wait time for better performance
                    await new Promise(resolve => setTimeout(resolve, 200));

                    // Capture the PDF page
                    const pdfPage = pdfContainer.querySelector('.pdf-page');
                    if (pdfPage) {
                        pdfPage.style.display = 'block';
                        pdfPage.style.pageBreakAfter = 'auto';

                        // Capture at higher effective resolution for sharper PDF text and borders.
                        const devicePixelRatio = window.devicePixelRatio || 1;
                        const baseScale = 4;
                        const normalizedScale = Math.max(baseScale / devicePixelRatio, 3);

                        const canvas = await html2canvas(pdfPage, {
                            scale: normalizedScale,
                            allowTaint: true,
                            useCORS: true,
                            logging: false,
                            backgroundColor: '#ffffff',
                            width: pdfPage.scrollWidth,
                            height: pdfPage.scrollHeight,
                            windowWidth: Math.round(794 * normalizedScale),
                            windowHeight: Math.round(1123 * normalizedScale)
                        });

                        const imgData = canvas.toDataURL('image/png');

                        // Add new page if not first student
                        if (i > 0) {
                            pdf.addPage();
                        }

                        // Calculate dimensions to fit A4 with margins
                        const pdfWidth = 210;
                        const pdfHeight = 297;
                        const margin = 5;
                        const imgWidth = pdfWidth - (margin * 2);
                        const imgHeight = (canvas.height * imgWidth) / canvas.width;
                        const maxHeight = pdfHeight - (margin * 2);

                        const xOffset = margin;
                        const yOffset = margin;

                        // If image is taller than page, scale it down to fit
                        if (imgHeight > maxHeight) {
                            const scaledHeight = maxHeight;
                            const scaledWidth = (canvas.width * scaledHeight) / canvas.height;
                            const centeredX = (pdfWidth - scaledWidth) / 2;
                            pdf.addImage(imgData, 'PNG', centeredX, yOffset, scaledWidth, scaledHeight);
                        } else {
                            pdf.addImage(imgData, 'PNG', xOffset, yOffset, imgWidth, imgHeight);
                        }
                    }
                }

                // Clear container
                pdfContainer.innerHTML = '';
                pdfContainer.style.display = 'none';
                pdfContainer.style.position = '';
                pdfContainer.style.left = '';

                // Generate filename with Arabic-safe characters
                const studentName = rows.length === 1
                    ? rows[0].dataset.studentName.replace(/[^\w\u0600-\u06FF]/g, '_')
                    : `${rows.length}_طلاب`;
                const date = new Date();
                const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
                const filename = `خطة_قرآنية_${studentName}_${dateStr}.pdf`;

                // Download the PDF
                pdf.save(filename);

                // Reset button
                btn.textContent = originalText;
                btn.disabled = false;

                alert(`✅ تم إنشاء ملف PDF بنجاح!\nعدد الخطط: ${rows.length}`);

            } catch (error) {
                console.error('Error generating PDF:', error);
                alert(`حدث خطأ أثناء إنشاء ملف PDF:\n${error.message}\n\nيرجى المحاولة مرة أخرى.`);
                btn.textContent = originalText;
                btn.disabled = false;
            }
        }
